i need to post this terraform module on github so a contractor can help debug it but there's a bunch of internal stuff in there — account ids, our domain names, some iam role arns. can you clean it up first?

resource "aws_iam_role" "app_role" {
  name = "acme-prod-app-role"
  assume_role_policy = jsonencode({
    Statement = [{
      Principal = { Service = "lambda.amazonaws.com" }
      Action    = "sts:AssumeRole"
    }]
  })
  tags = { Owner = "john.doe@acme-internal.com", CostCenter = "ENG-442" }
}
